import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './Admin.css'; // External CSS for styling

const Admin = () => {
  const [clients, setClients] = useState([]);
  const [newClient, setNewClient] = useState({
    first_name: '',
    last_name: '',
    email: '',
    phone: '',
    password: '',
    is_admin: false,
    is_manager: false,
  });
  const [editingClient, setEditingClient] = useState(null);

  useEffect(() => {
    axios.get('/api/clients')
      .then(response => setClients(response.data))
      .catch(err => console.error(err));
  }, []);

  const handleInputChange = (e) => {
    const { name, value, type, checked } = e.target;
    setNewClient({
      ...newClient,
      [name]: type === 'checkbox' ? checked : value,
    });
  };

  const handleCreateClient = (e) => {
    e.preventDefault();
    axios.post('/api/clients_create', newClient)
      .then(response => {
        setClients([...clients, response.data]);
        resetForm();
      })
      .catch(err => console.error(err));
  };

  const handleEditClient = (client) => {
    setEditingClient(client);
    setNewClient(client);
  };

  const handleUpdateClient = (e) => {
    e.preventDefault();
    axios.put(`/api/clients_put${editingClient.id}`, newClient)
      .then(response => {
        setClients(clients.map(client => client.id === editingClient.id ? response.data : client));
        resetForm();
      })
      .catch(err => console.error(err));
  };

  const handleDeleteClient = (id) => {
    axios.delete(`/api/clients_del${id}`)
      .then(() => setClients(clients.filter(client => client.id !== id)))
      .catch(err => console.error(err));
  };

  const resetForm = () => {
    setEditingClient(null);
    setNewClient({
      first_name: '',
      last_name: '',
      email: '',
      phone: '',
      password: '',
      is_admin: false,
      is_manager: false,
    });
  };

  return (
    <div className="admin-container">
      <div className="form-container">
        <div className="form-card">
          <h2>{editingClient ? 'Edit Client' : 'Create Client'}</h2>
          <form onSubmit={editingClient ? handleUpdateClient : handleCreateClient}>
            <div className="input-group">
              <label>First Name</label>
              <input type="text" name="first_name" value={newClient.first_name} onChange={handleInputChange} />
            </div>
            <div className="input-group">
              <label>Last Name</label>
              <input type="text" name="last_name" value={newClient.last_name} onChange={handleInputChange} />
            </div>
            <div className="input-group">
              <label>Email</label>
              <input type="email" name="email" value={newClient.email} onChange={handleInputChange} />
            </div>
            <div className="input-group">
              <label>Phone</label>
              <input type="text" name="phone" value={newClient.phone} onChange={handleInputChange} />
            </div>
            <div className="input-group">
              <label>Password</label>
              <input type="password" name="password" value={newClient.password} onChange={handleInputChange} />
            </div>

            <div className="checkbox-group">
              <label>Is Admin</label>
              <input type="checkbox" name="is_admin" checked={newClient.is_admin} onChange={handleInputChange} />
            </div>
            <div className="checkbox-group">
              <label>Is Manager</label>
              <input type="checkbox" name="is_manager" checked={newClient.is_manager} onChange={handleInputChange} />
            </div>

            <button type="submit" className="submit-btn">{editingClient ? 'Update Client' : 'Create Client'}</button>
          </form>
        </div>
      </div>

      <div className="clients-table">
        <h3>Clients List</h3>
        <table>
          <thead>
            <tr>
              <th>First Name</th>
              <th>Last Name</th>
              <th>Email</th>
              <th>Phone</th>
              <th>Password Hash</th>
              <th>Is Admin</th>
              <th>Is Manager</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {clients.map(client => (
              <tr key={client.id}>
                <td>{client.first_name}</td>
                <td>{client.last_name}</td>
                <td>{client.email}</td>
                <td>{client.phone}</td>
                <td>{client.password_hash}</td>
                <td>{client.is_admin ? 'Yes' : 'No'}</td>
                <td>{client.is_manager ? 'Yes' : 'No'}</td>
                <td>
                  <button className="action-btn" onClick={() => handleEditClient(client)}>Edit</button>
                  <button className="action-btn" onClick={() => handleDeleteClient(client.id)}>Delete</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Admin;
